// Həftənin gününə görə yemək seçimi
let day = "bazar ertəsi";
switch (day) {
  case "bazar ertəsi":
    console.log("Omlet yeyin!");
    break;
  case "çərşənbə axşamı":
    console.log("Pancake yeyin!");
    break;
  default:
    console.log("Tost yeyin!");
}
// nəticə: Omlet yeyin!

// switch ilə günə görə yemək seçimi
let day = "çərşənbə";
switch (day) {
  case "bazar ertəsi":
    console.log("Omlet yeyin!");
    break;
  case "çərşənbə axşamı":
    console.log("Pancake yeyin!");
    break;
  case "çərşənbə":
    console.log("Yulaf yeyin!");
    break;
  default:
    console.log("Tost yeyin!");
}
// nəticə: Yulaf yeyin!

// break olmadan switch
let day = "bazar ertəsi";
switch (day) {
  case "bazar ertəsi":
    console.log("Omlet yeyin!");
  case "çərşənbə axşamı":
    console.log("Pancake yeyin!");
  default:
    console.log("Tost yeyin!");
}
// nəticə: Omlet yeyin! Pancake yeyin! Tost yeyin! (break yoxdur, hamısı işləyir)

// switch ilə yemək seçimi
let day = "bazar ertəsi";
switch (day) {
  case "bazar ertəsi":
    console.log("Omlet yeyin!");
    break;
  default:
    console.log("Tost yeyin!");
}
// nəticə: Omlet yeyin!

// Eyni tapşırıq if...else ilə
if (day === "bazar ertəsi") {
  console.log("Omlet yeyin!");
} else {
  console.log("Tost yeyin!");
}
// nəticə: Omlet yeyin!

// Bir neçə case üçün eyni nəticə
let day = "şənbə";
switch (day) {
  case "şənbə":
  case "bazar":
    console.log("Həftəsonu yeməyi: Kreplər!");
    break;
  default:
    console.log("İş günü yeməyi: Tost!");
}
// nəticə: Həftəsonu yeməyi: Kreplər!

