// Choose a meal based on the day
let day = "Monday";
switch (day) {
  case "Monday":
    console.log("Eat an omelette!");
    break;
  case "Tuesday":
    console.log("Eat pancakes!");
    break;
  default:
    console.log("Eat toast!");
}
// Output: Eat an omelette!

// switch for day-based meal choice
let day = "Wednesday";
switch (day) {
  case "Monday":
    console.log("Eat an omelette!");
    break;
  case "Tuesday":
    console.log("Eat pancakes!");
    break;
  case "Wednesday":
    console.log("Eat oatmeal!");
    break;
  default:
    console.log("Eat toast!");
}
// Output: Eat oatmeal!

// switch without break
let day = "Monday";
switch (day) {
  case "Monday":
    console.log("Eat an omelette!");
  case "Tuesday":
    console.log("Eat pancakes!");
  default:
    console.log("Eat toast!");
}
// Output: Eat an omelette! Eat pancakes! Eat toast! (no break, all run)

// switch for meal choice
let day = "Monday";
switch (day) {
  case "Monday":
    console.log("Eat an omelette!");
    break;
  default:
    console.log("Eat toast!");
}
// Output: Eat an omelette!

// Same task with if...else
if (day === "Monday") {
  console.log("Eat an omelette!");
} else {
  console.log("Eat toast!");
}
// Output: Eat an omelette!

// Multiple cases with same outcome
let day = "Saturday";
switch (day) {
  case "Saturday":
  case "Sunday":
    console.log("Weekend meal: Crepes!");
    break;
  default:
    console.log("Weekday meal: Toast!");
}
// Output: Weekend meal: Crepes!

