// Выбор блюда по дню недели
let day = "понедельник";
switch (day) {
  case "понедельник":
    console.log("Ешь омлет!");
    break;
  case "вторник":
    console.log("Ешь блины!");
    break;
  default:
    console.log("Ешь тосты!");
}
// Вывод: Ешь омлет!

// switch для выбора блюда по дню
let day = "среда";
switch (day) {
  case "понедельник":
    console.log("Ешь омлет!");
    break;
  case "вторник":
    console.log("Ешь блины!");
    break;
  case "среда":
    console.log("Ешь овсянку!");
    break;
  default:
    console.log("Ешь тосты!");
}
// Вывод: Ешь овсянку!

// switch без break
let day = "понедельник";
switch (day) {
  case "понедельник":
    console.log("Ешь омлет!");
  case "вторник":
    console.log("Ешь блины!");
  default:
    console.log("Ешь тосты!");
}
// Вывод: Ешь омлет! Ешь блины! Ешь тосты! (без break все выполняется)

// switch для выбора блюда
let day = "понедельник";
switch (day) {
  case "понедельник":
    console.log("Ешь омлет!");
    break;
  default:
    console.log("Ешь тосты!");
}
// Вывод: Ешь омлет!

// Та же задача с if...else
if (day === "понедельник") {
  console.log("Ешь омлет!");
} else {
  console.log("Ешь тосты!");
}
// Вывод: Ешь омлет!

// Несколько case с одинаковым результатом
let day = "суббота";
switch (day) {
  case "суббота":
  case "воскресенье":
    console.log("Выходное блюдо: Крепы!");
    break;
  default:
    console.log("Будничное блюдо: Тосты!");
}
// Вывод: Выходное блюдо: Крепы!

